<?php session_start();Class SmsForm{    private $html;    private $write_sms;    private $dialog;    private $id_dialog;    private $id_button;    private $button;    private $width;    private $destinaires;    private $liste_sms;    private $signature;    private $liste_messages;    private $sms_types;    private $id_inter;    private $ref_chantier;    public function __construct($id_inter=0, $ref_chantier=0)    {        $this->id_inter = $id_inter;        $this->ref_chantier = $ref_chantier;        $this->write_sms = true;        $this->dialog = false;        $this->id_dialog = "dialog_form_simple";        $this->html = '';        $this->signature = "";        $this->liste_messages = false;    }    public function addDest($sms)    {        if(empty($this->destinaires))            $this->destinaires = $sms;        else            $this->destinaires .= ', '.$sms;    }    public function addListDest($liste)    {        $this->liste_sms = Array();        $this->liste_sms = $liste;        $this->write_sms = False;    }    private function html()    {        if($this->dialog)        {            if(is_file('./moduls/sms/blocs/button.inc'))            {                $id_button = $this->id_button;                $button = $this->button;                ob_start();                include('./moduls/sms/blocs/button.inc');                $this->html .= ob_get_contents();                ob_end_clean();            }        }                        //if($liste_messages)                                    if(is_file('./moduls/sms/blocs/form.inc'))        {            $id_inter = $this->id_inter;            $ref_chantier = $this->ref_chantier;            $liste_messages = $this->liste_messages;            $sms_types = $this->sms_types;            $write_sms = $this->write_sms;                        $smss = $this->destinaires;            $liste_smss = $this->liste_sms;            if($this->dialog)                $dialog = true;            $id_dialog = $this->id_dialog;            $titre =  $this->titre;            ob_start();            include('./moduls/sms/blocs/form.inc');            $this->html .= ob_get_contents();            ob_end_clean();            if($this->dialog)                $this->script();        }    }        public function displayListe()     {        $this->liste_messages = true;                global $db;        $db->Query('SELECT * FROM sms_types WHERE compte_principal="'.$_SESSION['compte_principal'].'" ');        while($row = $db->Row())        {            $this->sms_types[$row->id]['id'] = $row->id;            $this->sms_types[$row->id]['titre'] = $row->titre;            $this->sms_types[$row->id]['message'] = $row->message;        }            }        private function script()    {        if(is_file('./moduls/sms/blocs/script.inc'))        {            $id_button = $this->id_button;            $id_dialog = $this->id_dialog;            $width = $this->width;            ob_start();            include('./moduls/sms/blocs/script.inc');            $this->html .= ob_get_contents();            ob_end_clean();        }    }        private function parseMessage($mess)    {        $message = str_replace('%titre%', $this->genre, $mess);        $message = str_replace('%nom%', $this->nom, $message);        $message = str_replace('%prenom%', $this->prenom, $message);        $message = str_replace('%id_inter%', $this->id_inter, $message);        $message = str_replace('%ref_chantier%', $this->ref_chantier, $message);        return $message;    }    public function setToDialog($titre, $button='Envoyer sms', $id_button='dialog_form_btn2', $id_dialog='dialog_form2', $width="400")     {        $this->titre = $titre;        $this->dialog = true;        $this->id_button = $id_button;        $this->id_dialog = $id_dialog;        $this->button = $button;        $this->width = $width;    }    public function __toString()     {                $this->html();        if(AccesActivableModul('sms'))            return $this->html;                else            return '';    }        }?>